// // This module implements a 3-bit down-counter that decrements its count value on each positive edge of the clock signal. The counter resets to seven when the reset signal is asserted. It has a minimum count limit of zero (3'b000), at which point it wraps around back to seven. This counter can be used for applications that require counting events in reverse or generating timing sequences in reverse.
module top_module( clock, reset, count );input clock;
	input reset;
	output [2:0] count; 
	reg [2:0] count; 

	always @(posedge clock or  posedge reset) 
	begin 
		if  (reset) 
			count = 0;   
		else if  ( count < 3'b111 )  
			count = count + 1;   
		else 
			count = 0;   
	end 
endmodule
